mapper.select:
SELECT
a.order_no orderNo,
a.user_account userId,
a.user_register userAccount,
concat('VIP', a.vip_rank) vipRank,
a.adjust_way adjustWay,
a.order_status orderStatus,
a.adjust_type adjustType,
a.adjust_amount adjustAmount,
a.apply_time applyTime,
a.applicant applicant,
a.apply_reason applyReason
FROM user_manual_up_down_record a

    and a.site_code = #{vo.siteCode}
    AND a.adjust_way = 1

        AND a.apply_time  >=  #{vo.applyStartTime}


        AND a.apply_time  <=  #{vo.applyEndTime}


        AND a.order_no = #{vo.orderNo}


        AND a.user_account = #{vo.userId}


        AND a.user_register = #{vo.userAccount}


        AND a.order_status = #{vo.orderStatus}


        AND a.adjust_type = #{vo.adjustType}


        AND a.adjust_amount  >=  #{vo.adjustAmountMin}


        AND a.adjust_amount  <=  #{vo.adjustAmountMax}





        ORDER BY applyTime asc


        ORDER BY applyTime desc



        ORDER BY a.apply_time DESC

SELECT
'总计' orderNo,
IFNULL(SUM(a.adjust_amount), 0) adjustAmount
FROM user_manual_up_down_record a

    and a.site_code = #{vo.siteCode}
    AND a.adjust_way = 1

        AND a.order_no = #{vo.orderNo}


        AND a.user_account = #{vo.userAccount}


        AND a.audit_status = #{vo.auditStatus}


        AND a.adjust_type = #{vo.adjustType}


        AND a.adjust_amount  >=  #{vo.adjustAmountMin}


        AND a.adjust_amount  <=  #{vo.adjustAmountMax}


        AND a.apply_time  >=  #{vo.applyStartTime}


        AND a.apply_time  >=  #{vo.applyEndTime}

SELECT
count(1)
FROM user_manual_up_down_record a

    and a.site_code = #{vo.siteCode}
    AND a.adjust_way = 1

        AND a.apply_time  >=  #{vo.applyStartTime}


        AND a.apply_time  <=  #{vo.applyEndTime}


        AND a.order_no = #{vo.orderNo}


        AND a.user_id = #{vo.userId}


        AND a.user_account = #{vo.userAccount}


        AND a.order_status = #{vo.orderStatus}


        AND a.adjust_type = #{vo.adjustType}


        AND a.adjust_amount  >=  #{vo.adjustAmountMin}


        AND a.adjust_amount  <=  #{vo.adjustAmountMax}

SELECT a.id id, a.order_no orderNo, a.user_account userId, a.user_register userAccount, a.user_name userName, a.adjust_type adjustType, a.adjust_amount adjustAmount, a.apply_time applyTime, a.order_status orderStatus, a.lock_status lockStatus, IF(a.locker = #{adminName}, -1, 1) lockStatus1, a.locker locker, a.applicant applicant, a.one_reviewer oneReviewer FROM user_manual_up_down_record a
AND a.adjust_way = 1
AND a.order_status in (0,1)
AND a.order_status in (3,4)
AND a.apply_time >= #{vo.applyTimeStart}
AND a.apply_time <= #{vo.applyTimeEnd}
AND a.order_no = #{vo.orderNo}
AND a.lock_status = #{vo.lockStatus}
AND a.locker = #{vo.locker}
AND a.user_account = #{vo.userId}
AND a.user_register = #{vo.userAccount}
ORDER BY lockStatus1 ASC, a.lock_status ASC, a.apply_time ASC

SELECT
"总计" AS orderNo,
IFNULL(SUM(a.adjust_amount),0) AS adjustAmount
FROM
user_manual_up_down_record a

    AND a.adjust_way = 2

        AND a.created_time >= #{vo.creatorStartTime}


        AND a.created_time <= #{vo.creatorEndTime}


        AND a.order_no = #{vo.orderNo}


        AND a.user_name = #{vo.userName}


        AND a.user_account = #{vo.userAccount}


        AND a.order_status = #{vo.orderStatus}


        AND a.adjust_type = #{vo.adjustType}


        AND a.adjust_amount >= #{vo.minAdjustAmount}


        AND a.adjust_amount <= #{vo.maxAdjustAmount}

SELECT a.id id, a.order_no orderNo, a.user_account userId, a.user_register userAccount, a.user_name userName, a.order_status orderStatus, a.adjust_type adjustType, a.adjust_amount adjustAmount, a.apply_time applyTime, a.one_reviewer oneReviewer, a.two_reviewer twoReviewer, a.one_review_finish_time oneReviewFinishTime, a.two_review_finish_time twoReviewFinishTime, a.one_review_start_time oneReviewStartTime, a.two_review_start_time twoReviewStartTime, a.one_review_remark oneReviewRemark, a.two_review_remark twoReviewRemark FROM user_manual_up_down_record a
AND a.adjust_way = 1 AND a.order_status in (2,5,6)
AND a.apply_time >= #{vo.applyTimeStart}
AND a.apply_time <= #{vo.applyTimeEnd}
AND a.order_no = #{vo.orderNo}
AND a.user_id = #{vo.userId}
AND a.user_account = #{vo.userAccount}
AND a.order_status = #{vo.orderStatus}
ORDER BY a.updated_time DESC

SELECT
count(1)
FROM user_manual_up_down_record a

    AND a.adjust_way = 1
    AND a.order_status in (2,5,6)

        AND a.apply_ti6.me  >=  #{vo.applyTimeStart}


        AND a.apply_time  <=  #{vo.applyTimeEnd}


        AND a.order_no = #{vo.orderNo}


        AND a.user_id = #{vo.userId}


        AND a.user_account = #{vo.userAccount}


        AND a.order_status = #{vo.orderStatus}

SELECT
a.id id,
a.order_no orderNo,
a.user_account userAccount,
a.user_register userRegister,
a.apply_amount applyAmount,
a.status status,
a.file_key applyFile,
a.cash_flow_file cashFlowFile,
a.lock_status lockStatus,
IF(a.locker = #{adminName}, -1, 1) lockStatus1,
a.locker locker,
a.deposit_withdraw_type depositWithdrawType,
a.deposit_withdraw_method depositWithdrawMethod,
a.currency,
a.trade_currency_amount tradeCurrencyAmount,
a.exchange_rate exchangeRate,
a.fee_rate feeRate,
/*a.first_audit_user oneReviewer,*/
a.account_type accountType,
a.account_branch accountBranch
/*a.withdraw_address withdrawAddress,*/
/*a.withdraw_name withdrawName*/
FROM user_deposit_withdrawal a

    AND a.type = 1


            AND a.status in (1,2)


            AND a.status in (4,5)



        AND a.created_time  >=  #{vo.applyTimeStart}


        AND a.created_time  <=  #{vo.applyTimeEnd}


        AND a.order_no = #{vo.orderNo}


        AND a.lock_status = #{vo.lockStatus}


        AND a.locker = #{vo.locker}


        AND a.user_account = #{vo.userAccount}


        AND a.user_register = #{vo.userRegister}


        AND a.user_name = #{vo.userName}


ORDER BY lockStatus1 ASC, a.lock_status ASC, a.created_time ASC

SELECT
a.id id,
a.order_no orderNo,
a.user_account userAccount,
a.user_register userRegister,
a.status status,
a.apply_amount applyAmount,
a.arrive_amount arriveAmount,
a.created_time applyTime,
a.file_key applyFile,
a.remark remark,
a.cash_flow_file cashFlowFile
FROM user_deposit_withdrawal a

    AND a.type = 1
    AND a.status in (3,101)
    /* deposit_withdraw_type deposit_withdraw_method*/
    -- AND a.deposit_withdraw_method in ('local_bank_card','local_alipay','local_wechat')


        AND a.created_time  >=  #{vo.applyTimeStart}


        AND a.created_time  <=  #{vo.applyTimeEnd}


        AND a.order_no = #{vo.orderNo}


        AND a.user_account = #{vo.userAccount}


        AND a.user_register = #{vo.userRegister}


        AND a.user_name = #{vo.userName}


        AND a.status = #{vo.orderStatus}


ORDER BY a.updated_time DESC

SELECT
count(1)
FROM user_deposit_withdrawal a

    AND a.type = 1
    -- AND a.payment_method in ('local_bank_card','local_alipay','local_wechat')
    AND a.status in (3,101)

        AND a.created_time  >=  #{vo.applyTimeStart}


        AND a.created_time  <=  #{vo.applyTimeEnd}


        AND a.order_no = #{vo.orderNo}


        AND a.user_account = #{vo.userAccount}


        AND a.user_name = #{vo.userName}


        AND a.status = #{vo.orderStatus}

SELECT b.userAccount as userAccount FROM ( SELECT a.userAccount, sum( a.amount ) AS resultAmount FROM ( SELECT user_account AS userAccount, SUM( adjust_amount ) AS amount FROM user_manual_up_down_record WHERE adjust_way = 1 AND adjust_type = 3 AND order_status = 6
AND agent_id in
#{value}
AND updated_time >= #{vo.startTime}
AND updated_time <= #{vo.endTime}
GROUP BY user_account UNION ( SELECT user_account AS userAccount, SUM( arrive_amount ) AS amount FROM user_deposit_withdrawal WHERE type = 1
AND agent_id in
#{value}
AND updated_time >= #{vo.startTime}
AND updated_time <= #{vo.endTime}
AND STATUS = 101 GROUP BY user_account ) union ( SELECT user_account AS userAccount, SUM( amount ) AS amount FROM agent_deposit_subordinates WHERE 1 = 1
AND agent_id in
#{value}
AND deposit_time >= #{vo.startTime}
AND deposit_time <= #{vo.endTime}
GROUP BY user_account ) ) a GROUP BY a.userAccount ) b
WHERE b.resultAmount >= #{vo.validAmount}

SELECT
t.agent_account as agentAccount,
IFNULL(SUM(t.adjust_amount),0) as amount,
IFNULL(SUM(t.fee_amount),0) as feeAmount,
u.main_currency as currency
FROM
user_manual_up_down_record t
inner join user_info u on u.user_account = t.user_account
WHERE
u.account_type in (2, 3)
and t.audit_status = 3
and t.adjust_way = #{vo.manualOperateType}

    AND t.adjust_type in

        #{adjustType}



    AND t.agent_account in

        #{agentAccount}



    AND t.agent_id in

        #{agentId}



    AND u.main_currency = #{vo.currency}

and t.updated_time  >=  #{vo.startTime}
AND t.updated_time  <=  #{vo.endTime}
GROUP BY
t.agent_account, u.main_currency

SELECT id, site_code AS siteCode, agent_id AS agentId, agent_account AS agentAccount, user_account AS userAccount, user_id AS userId, user_name AS userName, vip_grade_code AS vipGradeCode, order_no AS orderNo, adjust_way AS adjustWay, adjust_type AS adjustType, activity_template AS activityTemplate, activity_id AS activityId, currency_code AS currencyCode, adjust_amount AS adjustAmount, running_water_multiple AS runningWaterMultiple, certificate_address AS certificateAddress, apply_reason AS applyReason, apply_time AS applyTime, applicant AS applicant, audit_datetime AS auditDatetime, audit_id AS auditId, audit_remark AS auditRemark, audit_status AS auditStatus, review_operation AS reviewOperation, lock_status AS lockStatus, locker AS locker, IF(locker = #{vo.operator}, -1, 1) as lockStatus1 FROM user_manual_up_down_record WHERE site_code = #{vo.siteCode} AND review_operation = #{vo.reviewOperation}
AND apply_time >= #{vo.applyTimeStart}
AND apply_time <= #{vo.applyTimeEnd}
AND user_account = #{vo.userAccount}
AND order_no = #{vo.orderNo}
AND lock_status = #{vo.lockStatus}
AND locker = #{vo.locker}
ORDER BY lockStatus1 ASC, lock_status ASC, apply_time ASC

SELECT user_id as userId, currency_code as currencyCode , sum(adjust_amount) as depositAmount FROM user_manual_up_down_record WHERE adjust_way = 1 AND adjust_type = 4 AND balance_change_status = 1
AND agent_id IN
#{value}
and updated_time >= #{vo.startTime}
and updated_time <= #{vo.endTime}
GROUP BY user_id, currency_code
